        var current = num
        var depth = 0
        while current != 1 {
            current = BitPattern(current).popcount()
            depth += 1
        }
        popcountDepth.append(depth)
    }

    // Create a 2D array to store the count of each depth in ranges
    // Since k can be up to 5, we can use a 2D array of size n x 6
    let n = nums.count
    var depthCounts: [[Int]] = Array(repeating: Array(repeating: 0, count: 6), count: n)

    // Initialize depthCounts with the initial popcount depths
    for i in 0..<n {
        let d = Int(popcountDepth[i])
        if d <= 5 {
            depthCounts[i][d] = 1
        }
    }

    // Build prefix sums for each depth
    var prefixSums: [[Int]] = Array(repeating: Array(repeating: 0, count: 6), count: n + 1)
    for i in 1..<n + 1 {
        for d in 0..<6 {
            prefixSums[i][d] = prefixSums[i - 1][d] + depthCounts[i - 1][d]
        }
    }

    // Process queries
    var answer: [Int64] = []
    for query in queries {
        if query[0] == 1 {
            let l = query[1]
            let r = query[2]
            let k = query[3]
            let count = prefixSums[r + 1][k] - prefixSums[l][k]
            answer.append(Int64(count))
        } else {
            let idx = query[1]
            let val = query[2]
            // Update the number at idx
            let oldNum = nums[idx]
            let newNum = val
            nums[idx] = newNum

